fun newCacheKey(
    request: ImageRequest,
    mappedData: Any,
    options: Options,
    eventListener: EventListener,
): MemoryCache.Key? {
    // Fast path: read and write are both disabled.
    if (request.memoryCachePolicy == CachePolicy.DISABLED) {
        return null
    }

    // Fast path: an explicit memory cache key has been set.
    if (request.memoryCacheKey != null) {
        return MemoryCache.Key(request.memoryCacheKey, request.memoryCacheKeyExtras)
    }

    // Slow path: create a new memory cache key.
    eventListener.keyStart(request, mappedData)
    val key = imageLoader.components.key(mappedData, options, logger, TAG)
    eventListener.keyEnd(request, key)
    if (key == null) {
        return null
    }

    // Else, create a memory cache key with all extras.
    if (request.transformations.isNotEmpty()) {
        val extras = request.memoryCacheKeyExtras.toMutableMap()
        extras[EXTRA_SIZE] = options.size.toString()
        return MemoryCache.Key(key, extras)
    } else {
        return MemoryCache.Key(key, request.memoryCacheKeyExtras)
    }
}

override fun get(context: ResolutionContext): T {
    if (context.scope.scopeQualifier != beanDefinition.scopeQualifier && context.scopeArchetype != beanDefinition.scopeQualifier) {
        error("Wrong Scope qualifier: trying to open instance for ${context.scope.id} in $beanDefinition")
    }

    // Fast path: check if already created without locking
    val existing = values[context.scope.id]
    if (existing != null) {
        return existing
    }

    // Slow path: need to create the instance with locking
    return KoinPlatformTools.synchronized(this) {
        // Double-check inside lock to avoid race condition
        val doubleCheck = values[context.scope.id]
        if (doubleCheck != null) {
            doubleCheck
        } else {
            if (!holdInstance) {
                throw MissingScopeValueException("No value for scope '${context.scope.id}' in $beanDefinition")
            }
            val created = super.create(context)
            if (holdInstance) {
                values[context.scope.id] = created
            }
            created
        }
    }
}

fun <D : Operation.Data> parse(
    jsonReader: JsonReader,
    operation: Operation<D>,
    requestUuid: Uuid?,
    customScalarAdapters: CustomScalarAdapters,
    deferredFragmentIds: Set<DeferredFragmentIdentifier>?,
): ApolloResponse<D> {
  jsonReader.beginObject()

  var data: D? = null
  var errors: List<Error>? = null
  var extensions: Map<String, Any?>? = null
  while (jsonReader.hasNext()) {
    @Suppress("UNCHECKED_CAST")
    when (val name = jsonReader.nextName()) {
      "data" -> {
        val falseVariables = operation.falseVariables(customScalarAdapters)
        data = operation.parseData(jsonReader, customScalarAdapters, falseVariables, deferredFragmentIds, errors)
      }

      "errors" -> errors = jsonReader.readErrors()
      "extensions" -> extensions = jsonReader.readAny() as? Map<String, Any?>
      else -> {
        if (!jsonReader.ignoreUnknownKeys()) {
          throw JsonDataException("Unknown key '$name' found at path: '${jsonReader.getPath().joinToString(".")}'")
        }
        jsonReader.skipValue()
      }
    }
  }

  jsonReader.endObject()

  return ApolloResponse.Builder(operation = operation, requestUuid = requestUuid ?: uuid4())
      .errors(errors)
      .data(data)
      .extensions(extensions)
      .build()
}

private fun possibleTypesInternal(allTypes: List<CompiledType>, type: CompiledNamedType): List<ObjectType> {
  return when (type) {
    is ObjectType -> listOf(type)
    is UnionType -> type.members.toList()
    is InterfaceType -> {
      allTypes.flatMap { possibleImplementation ->
        when (possibleImplementation) {
          is ObjectType -> {
            if (possibleImplementation.implements.any { it.name == type.name }) {
              possibleTypesInternal(allTypes, possibleImplementation)
            } else {
              emptyList()
            }
          }
          is InterfaceType -> {
            if (possibleImplementation.implements.any { it.name == type.name }) {
              possibleTypesInternal(allTypes, possibleImplementation)
            } else {
              emptyList()
            }
          }
          else -> emptyList()
        }
      }
    }
    else -> error("Type '$type' can only have one possible type")
  }
}

private fun readVariableUnicodeEscape(): Int {
  var i = 0
  var result = 0

  // An int32 has 8 hex digits max
  while (i < 9) {
    if (pos == len) {
      throw LexerException("Unterminated Unicode escape", pos, line, column(pos), null)
    }
    val c = src[pos++]

    if (c == '}') {
      if (i == 0) {
        val start = pos - i - 4
        // empty unicode escape?
        throw LexerException("Invalid Unicode escape '${src.substring(start, pos)}'", start, line, column(start), null)
      }

      if (!result.isUnicodeScalar()) {
        val start = pos - i - 4
        throw LexerException("Invalid Unicode escape '${src.substring(start, pos)}'", start, line, column(start), null)
      }

      // Verify that the code point is valid?
      return result
    }

    val h = c.decodeHex()
    if (h == -1) {
      val start = pos - i - 4
      throw LexerException("Invalid Unicode escape '${src.substring(start, pos)}'", start, line, column(start), null)
    }

    result = result.shl(4).or(h)
    i++
  }

  val start = pos - i - 3
  throw LexerException("Invalid Unicode escape '${src.substring(start, pos)}'", start, line, column(start), null)
}

private fun parseFragment(): GQLSelection {
  val start = token
  expectToken<Token.Spread>()

  val on = expectOptionalKeyword("on")
  return if (on == null && peek<Token.Name>()) {
    val name = parseFragmentName()
    val arguments: List<GQLArgument>
    if (allowFragmentArguments) {
      arguments = parseArguments(false)
    } else {
      arguments = emptyList()
    }
    val directives = parseDirectives(const = false)
    GQLFragmentSpread(
        sourceLocation = sourceLocation(start),
        name = name,
        arguments = arguments,
        directives = directives,
    )
  } else {
    val typeCondition = if (on != null) parseNamedType() else null
    val directives = parseDirectives(const = false)
    val selections = parseSelectionSet()
    GQLInlineFragment(
        sourceLocation = sourceLocation(start),
        typeCondition = typeCondition,
        directives = directives,
        selections = selections
    )
  }
}

private fun parseOperationDefinition(start: Token): GQLOperationDefinition {
  val description = expectOptionalToken<Token.String>()?.value

  if (peek<Token.LeftBrace>()) {
    val selections = parseSelectionSet()
    return GQLOperationDefinition(
        sourceLocation = sourceLocation(start),
        operationType = "query",
        name = null,
        variableDefinitions = emptyList(),
        directives = emptyList(),
        selections = selections,
        description = description
    )
  }

  val operationType = parseOperationType()

  val name = if (token is Token.Name) {
    parseName()
  } else {
    null
  }

  val variableDefinitions = parseVariableDefinitions()
  val directives = parseDirectives(const = false)
  val selections = parseSelectionSet()
  return GQLOperationDefinition(
      sourceLocation = sourceLocation(start),
      operationType = operationType,
      name = name,
      variableDefinitions = variableDefinitions,
      directives = directives,
      selections = selections,
      description = description
  )
}

private fun parseDefinition(): GQLDefinition {
  val start = token
  val hasDescription = peek<Token.String>()
  val t = if (hasDescription) lookaheadToken() else token

  return when (t) {
    is Token.LeftBrace -> parseOperationDefinition(start)
    is Token.Name -> {
      when (t.value) {
        "schema" -> parseSchemaDefinition(start)
        "scalar" -> parseScalarTypeDefinition(start)
        "type" -> parseObjectTypeDefinition(start)
        "interface" -> parseInterfaceTypeDefinition(start)
        "union" -> parseUnionTypeDefinition(start)
        "enum" -> parseEnumTypeDefinition(start)
        "input" -> parseInputObjectTypeDefinition(start)
        "directive" -> parseDirectiveDefinition(start)
        "query", "mutation", "subscription" -> parseOperationDefinition(start)
        "fragment" -> parseFragmentDefinition(start)
        "extend" -> {
          if (hasDescription) {
            throw ParserException("Type system extensions cannot have a description", t)
          }
          parseTypeSystemExtension()
        }
        "service" -> {
          if (!allowServiceCapabilities) {
            unexpected(t)
          }
          parseServiceDefinition(start)
        }
        else -> unexpected(t)
      }
    }

    else -> unexpected()
  }
}

private fun parseValueInternal(const: Boolean): GQLValue {
  return when (val t = token) {
    is Token.LeftBracket -> parseList(const)
    is Token.LeftBrace -> parseObject(const)

    is Token.Int -> GQLIntValue(sourceLocation(), t.value).also { advance() }
    is Token.Float -> GQLFloatValue(sourceLocation(), t.value).also { advance() }
    is Token.String -> GQLStringValue(sourceLocation(), t.value).also { advance() }
    is Token.Name -> when (t.value) {
      "true" -> GQLBooleanValue(sourceLocation(), true).also { advance() }
      "false" -> GQLBooleanValue(sourceLocation(), false).also { advance() }
      "null" -> GQLNullValue(sourceLocation()).also { advance() }
      else -> GQLEnumValue(sourceLocation(), t.value).also { advance() }
    }

    is Token.Dollar -> {
      val start = token
      advance()
      if (const) {
        val n = expectOptionalToken<Token.Name>()
        if (n != null) {
          throw ParserException("Unexpected variable '${n.value}' in constant value.", n)
        } else {
          unexpected(n)
        }
      }
      val name = parseName()
      GQLVariableValue(
          sourceLocation = sourceLocation(start),
          name = name
      )
    }

    else -> unexpected()
  }
}

override fun visitConstantExpression(expression: KtConstantExpression) {
    val elementType = expression.iElementType
    if (elementType != KtNodeTypes.INTEGER_CONSTANT && elementType != KtNodeTypes.FLOAT_CONSTANT) return

    if (isIgnoredByConfig(expression) ||
        expression.isPartOfFunctionReturnConstant() ||
        expression.isPartOfConstructorOrFunctionConstant()
    ) {
        return
    }

    val parent = expression.parent
    val rawNumber = if (parent.hasUnaryMinusPrefix()) {
        parent.text
    } else {
        expression.text
    }

    val number = parseAsDoubleOrNull(rawNumber)
    if (number != null && !ignoreNumbers.contains(number)) {
        report(
            Finding(
                Entity.from(expression),
                "This expression contains a magic number." +
                    " Consider defining it to a well named constant."
            )
        )
    }
}

internal suspend fun transform(
    result: ExecuteResult,
    request: ImageRequest,
    options: Options,
    eventListener: EventListener,
    logger: Logger?,
): ExecuteResult {
    val transformations = request.transformations
    if (transformations.isEmpty()) {
        return result
    }

    // Skip the transformations as converting to a bitmap is disabled.
    val image = result.image
    if (image !is BitmapImage && !request.allowConversionToBitmap) {
        logger?.log(TAG, Logger.Level.Info) {
            val type = result.image::class.simpleName
            "allowConversionToBitmap=false, skipping transformations for type $type."
        }
        return result
    }

    // Apply the transformations.
    val input = convertImageToBitmap(image, options, transformations, logger)
    eventListener.transformStart(request, input)
    val output = transformations.foldIndices(input) { bitmap, transformation ->
        transformation.transform(bitmap, options.size).also { coroutineContext.ensureActive() }
    }
    eventListener.transformEnd(request, output)
    return result.copy(image = output.asImage())
}

fun <T> registerArguments(sqlType: IColumnType<*>, arguments: Iterable<T>) {
    val sqlTypeT = (sqlType as IColumnType<T>)

    // avoid potentially expensive valueToString call unless we need to sort values
    if (arguments is Collection && arguments.size <= 1) {
        arguments.forEach {
            if (prepared) {
                _args.add(sqlType to it)
                append(sqlTypeT.parameterMarker(it))
            } else {
                append(sqlTypeT.valueToString(it))
            }
        }
    } else {
        fun toString(value: T) = when {
            prepared && value is String -> value
            else -> sqlTypeT.valueToString(value)
        }

        arguments.map { it to toString(it) }
            .sortedBy { it.second }
            .appendTo {
                if (prepared) {
                    _args.add(sqlType to it.first)
                    append(sqlTypeT.parameterMarker(it.first))
                } else {
                    append(it.second)
                }
            }
    }
}

private class SemaphoreSegment(id: Long, prev: SemaphoreSegment?, pointers: Int) : Segment<SemaphoreSegment>(id, prev, pointers) {
    val acquirers = atomicArrayOfNulls<Any?>(SEGMENT_SIZE)
    override val numberOfSlots: Int get() = SEGMENT_SIZE

    @Suppress("NOTHING_TO_INLINE")
    inline fun get(index: Int): Any? = acquirers[index].value

    @Suppress("NOTHING_TO_INLINE")
    inline fun set(index: Int, value: Any?) {
        acquirers[index].value = value
    }

    @Suppress("NOTHING_TO_INLINE")
    inline fun cas(index: Int, expected: Any?, value: Any?): Boolean = acquirers[index].compareAndSet(expected, value)

    @Suppress("NOTHING_TO_INLINE")
    inline fun getAndSet(index: Int, value: Any?) = acquirers[index].getAndSet(value)

    // Cleans the acquirer slot located by the specified index
    // and removes this segment physically if all slots are cleaned.
    override fun onCancellation(index: Int, cause: Throwable?, context: CoroutineContext) {
        // Clean the slot
        set(index, CANCELLED)
        // Remove this segment if needed
        onSlotCleaned()
    }

    override fun toString() = "SemaphoreSegment[id=$id, hashCode=${hashCode()}]"
}

private fun holdsLockImpl(owner: Any?): Int {
    while (true) {
        // Is this mutex locked?
        if (!isLocked) return HOLDS_LOCK_UNLOCKED
        val curOwner = this.owner.value
        // Wait in a spin-loop until the owner is set
        if (curOwner === NO_OWNER) continue // <-- ATTENTION, BLOCKING PART HERE
        // Check the owner
        return if (curOwner === owner) HOLDS_LOCK_YES else HOLDS_LOCK_ANOTHER_OWNER
    }
}

override suspend fun lock(owner: Any?) {
    if (tryLock(owner)) return
    lockSuspend(owner)
}

private suspend fun lockSuspend(owner: Any?) = suspendCancellableCoroutineReusable<Unit> { cont ->
    val contWithOwner = CancellableContinuationWithOwner(cont, owner)
    acquire(contWithOwner)
}

override fun tryLock(owner: Any?): Boolean = when (tryLockImpl(owner)) {
    TRY_LOCK_SUCCESS -> true
    TRY_LOCK_FAILED -> false
    TRY_LOCK_ALREADY_LOCKED_BY_OWNER -> error("This mutex is already locked by the specified owner: $owner")
    else -> error("unexpected")
}

override fun decodeElementIndex(descriptor: SerialDescriptor): Int {
    val index = when (mode) {
        WriteMode.OBJ -> decodeObjectIndex(descriptor)
        WriteMode.MAP -> decodeMapIndex()
        else -> decodeListIndex() // Both for LIST and default polymorphic
    }
    // The element of the next index that will be decoded
    if (mode != WriteMode.MAP) {
        lexer.path.updateDescriptorIndex(index)
    }
    return index
}

private fun decodeMapIndex(): Int {
    var hasComma = false
    val decodingKey = currentIndex % 2 != 0
    if (decodingKey) {
        if (currentIndex != -1) {
            hasComma = lexer.tryConsumeComma()
        }
    } else {
        lexer.consumeNextToken(COLON)
    }

    return if (lexer.canConsumeValue()) {
        if (decodingKey) {
            if (currentIndex == -1) lexer.require(!hasComma) { "Unexpected leading comma" }
            else lexer.require(hasComma) { "Expected comma after the key-value pair" }
        }
        ++currentIndex
    } else {
        if (hasComma && !json.configuration.allowTrailingComma) lexer.invalidTrailingComma()
        CompositeDecoder.DECODE_DONE
    }
}

public class RootRouteSelector(rootPath: String = "") : RouteSelector(), RoutePathComponent {

    private val parts = RoutingPath.parse(rootPath).parts.map {
        require(it.kind == RoutingPathSegmentKind.Constant) {
            "rootPath should be constant, no wildcards supported."
        }
        it.value
    }

    private val successEvaluationResult = RouteSelectorEvaluation.Success(
        RouteSelectorEvaluation.qualityConstant,
        segmentIncrement = parts.size
    )

    override suspend fun evaluate(context: RoutingResolveContext, segmentIndex: Int): RouteSelectorEvaluation {
        check(segmentIndex == 0) { "Root selector should be evaluated first." }
        if (parts.isEmpty()) {
            return RouteSelectorEvaluation.Constant
        }

        val parts = parts
        val segments = context.segments
        if (segments.size < parts.size) {
            return RouteSelectorEvaluation.FailedPath
        }

        for (index in segmentIndex until segmentIndex + parts.size) {
            if (segments[index] != parts[index]) {
                return RouteSelectorEvaluation.FailedPath
            }
        }

        return successEvaluationResult
    }

    override fun toString(): String =
        parts.joinToString("/")
}

override suspend fun evaluate(context: RoutingResolveContext, segmentIndex: Int): RouteSelectorEvaluation {
        val segments = context.segments
        if (prefix.isNotEmpty()) {
            val segmentText = segments.getOrNull(segmentIndex)
            if (segmentText == null || !segmentText.startsWith(prefix)) {
                return RouteSelectorEvaluation.FailedPath
            }
        }

        val values = when {
            name.isEmpty() -> parametersOf()
            else -> parametersOf(
                name,
                segments.drop(segmentIndex).mapIndexed { index, segment ->
                    if (index == 0) {
                        segment.drop(prefix.length)
                    } else {
                        segment
                    }
                }
            )
        }
        val quality = when {
            segmentIndex < segments.size -> RouteSelectorEvaluation.qualityTailcard
            else -> RouteSelectorEvaluation.qualityMissing
        }
        return RouteSelectorEvaluation.Success(
            quality,
            values,
            segmentIncrement = segments.size - segmentIndex
        )
    }

    override fun toString(): String = "{...}"

private fun cacheInterceptors(): List<PipelineInterceptor<TSubject, TContext>> {
    val interceptorsQuantity = interceptorsQuantity
    if (interceptorsQuantity == 0) {
        notSharedInterceptorsList(emptyList())
        return emptyList()
    }

    val phases = phasesRaw
    if (interceptorsQuantity == 1) {
        for (phaseIndex in 0..phases.lastIndex) {
            @Suppress("UNCHECKED_CAST")
            val phaseContent =
                phases[phaseIndex] as? PhaseContent<TSubject, TContext> ?: continue

            if (phaseContent.isEmpty) continue

            val interceptors = phaseContent.sharedInterceptors()
            setInterceptorsListFromPhase(phaseContent)
            return interceptors
        }
    }

    val destination: MutableList<PipelineInterceptor<TSubject, TContext>> = mutableListOf()
    for (phaseIndex in 0..phases.lastIndex) {
        @Suppress("UNCHECKED_CAST")
        val phase = phases[phaseIndex] as? PhaseContent<TSubject, TContext> ?: continue

        phase.addTo(destination)
    }

    notSharedInterceptorsList(destination)
    return destination
}

private fun fastPathMerge(from: Pipeline<TSubject, TContext>): Boolean {
    if (from.phasesRaw.isEmpty()) {
        return true
    }

    if (phasesRaw.isNotEmpty()) {
        return false
    }

    val fromPhases = from.phasesRaw

    for (index in 0..fromPhases.lastIndex) {
        val fromPhaseOrContent = fromPhases[index]
        if (fromPhaseOrContent is PipelinePhase) {
            phasesRaw.add(fromPhaseOrContent)
            continue
        }

        if (fromPhaseOrContent !is PhaseContent<*, *>) {
            continue
        }

        @Suppress("UNCHECKED_CAST")
        fromPhaseOrContent as PhaseContent<TSubject, TContext>

        phasesRaw.add(
            PhaseContent(
                fromPhaseOrContent.phase,
                fromPhaseOrContent.relation,
                fromPhaseOrContent.sharedInterceptors()
            )
        )
        continue
    }

    interceptorsQuantity += from.interceptorsQuantity
    setInterceptorsListFromAnotherPipeline(from)
    return true
}

private fun buildFieldOfType(
    path: List<Any>,
    id: String,
    mergedField: CompiledField,
    resolver: FakeResolver,
    value: Optional<Any?>,
    type: CompiledType,
    customScalarAdapters: CustomScalarAdapters,
    parentType: String,
    parent: Map<String, Any?>
): Any? {
  if (value is Optional.Present && value.value is Optional.Absent) {
    // Shortcut to allow omitting a value for `@skip` directives
    return Optional.Absent
  }
  if (type !is CompiledNotNullType) {
    return if (value is Optional.Present) {
      if (value.value == null) {
        null
      } else {
        buildFieldOfType(path, id, mergedField, resolver, value, CompiledNotNullType(type), customScalarAdapters, parentType, parent)
      }
    } else {
      if (resolver.resolveMaybeNull(FakeResolverContext(path, id, mergedField, customScalarAdapters, parentType, parent))) {
        null
      } else {
        buildFieldOfType(path, id, mergedField, resolver, value, CompiledNotNullType(type), customScalarAdapters, parentType, parent)
      }
    }
  }

  return buildFieldOfNonNullType(path, id, mergedField, resolver, value, type.ofType, customScalarAdapters, parentType, parent)
}

private fun GQLField.validateCatches(fieldDefinition: GQLFieldDefinition) {
  val catches = directives.filter {
    schema.originalDirectiveName(it.name) == Schema.CATCH
  }

  if (catches.size > 1) {
    // "caught" (ahah) by other validation rules
    return
  }

  val catch = catches.singleOrNull()
  if (catch == null) {
    return
  }

  val levels = catch.getArgumentValueOrDefault("levels", schema)
  val maxDimension = fieldDefinition.type.maxDimension()
  if (levels is GQLListValue) {
    levels.values.forEach {
      if (it is GQLIntValue) {
        val asInt = it.value.toIntOrNull()
        if (asInt == null) {
          registerIssue("Invalid value: '${it.value}'", it.sourceLocation)
          return@forEach
        }
        if (asInt > maxDimension) {
          registerIssue(
              message = "Invalid 'levels' value '$asInt' for `@catch` usage: this field has a max list level of $maxDimension",
              sourceLocation = it.sourceLocation
          )
        } else if (asInt < 0) {
          registerIssue(
              message = "'levels' values must be positive ints",
              sourceLocation = it.sourceLocation
          )
        }
      }
    }
  }
}

private fun ExtensionsMerger.mergeDirectives(
    list: List<GQLDirective>,
    other: List<GQLDirective>,
    filter: (GQLDirective) -> Boolean = { true },
): List<GQLDirective> {
  val result = mutableListOf<GQLDirective>()

  result.addAll(list)
  for (directiveToAdd in other) {
    if (!filter(directiveToAdd)) {
      continue
    }

    if (result.any { it.name == directiveToAdd.name }) {
      // duplicated directive, get the definition to see if we can
      val definition = directiveDefinitions[directiveToAdd.name]

      if (definition == null) {
        issues.add(OtherValidationIssue("Cannot find directive definition `${directiveToAdd.name}`", directiveToAdd.sourceLocation))
        continue
      } else if (!definition.repeatable) {
        issues.add(OtherValidationIssue("Cannot add non-repeatable directive `${directiveToAdd.name}`", directiveToAdd.sourceLocation))
        continue
      }
    }
    result.add(directiveToAdd)
  }

  return result
}

internal fun syntheticSchemaDefinition(typeDefinitions: Map<String, GQLTypeDefinition>): GQLSchemaDefinition? {
  val operationTypeDefinitions = listOf("query", "mutation", "subscription").mapNotNull {
    // 3.3.1
    // If there is no schema definition, look for an object type named after the operationType
    // i.e. Query, Mutation, ...

    val typeName = when (it) {
      "query" -> "Query"
      "mutation" -> "Mutation"
      "subscription" -> "Subscription"
      else -> error("")
    }

    val typeDefinition = typeDefinitions[typeName]
    if (typeDefinition == null) {
      if (it == "query") {
        return null
      }
      return@mapNotNull null
    }

    GQLOperationTypeDefinition(
        operationType = it,
        namedType = typeName
    )
  }

  return GQLSchemaDefinition(description = null, directives = emptyList(), rootOperationTypeDefinitions = operationTypeDefinitions
  )
}

private fun List<GQLSelection>.validate(
    parentType: String,
    path: List<String>,
    operation: GQLOperationDefinition?,
    visitedFragmentSpreads: Set<String>,
) {
  forEach {
    when (it) {
      is GQLField -> {
        val typeDefinition = schema.typeDefinitions.get(parentType) ?: return@forEach
        val fieldDefinition = it.definitionFromScope(schema, typeDefinition) ?: return@forEach
        it.selections.validate(fieldDefinition.type.rawType().name, path + it.responseName(), null, visitedFragmentSpreads)
      }

      is GQLFragmentSpread -> {
        it.directives.validate(operation, path)

        if (visitedFragmentSpreads.contains(it.name)) {
          // This fragment is cyclic
          return@forEach
        }
        val fragmentDefinition = fragments.get(it.name) ?: return@forEach
        fragmentDefinition.selections.validate(fragmentDefinition.typeCondition.name, path, null, visitedFragmentSpreads + it.name)
      }

      is GQLInlineFragment -> {
        it.directives.validate(operation, path)
        it.selections.validate(it.typeCondition?.name ?: parentType, path, null, visitedFragmentSpreads)
      }
    }
  }
}

internal fun ValidationScope.validateVariableUsage(
    variableUsage: VariableUsage,
    variableDefinitions: List<GQLVariableDefinition>,
    context: String,
) {
  val variable = variableUsage.variable
  val variableDefinition = variableDefinitions.firstOrNull { it.name == variable.name }
  if (variableDefinition == null) {
    registerIssue(
        message = "Variable `${variable.name}` is not defined by $context",
        sourceLocation = variable.sourceLocation
    )
    return
  }

  if (variableUsage.isOneOfInputField && variableDefinition.type !is GQLNonNullType) {
    registerIssue(
        message = "Variable `${variable.name}` of type `${variableDefinition.type.pretty()}` used in a OneOf input type must be a non-null type",
        sourceLocation = variable.sourceLocation
    )
  }

  if (!isVariableUsageAllowed(variableDefinition = variableDefinition, usage = variableUsage)) {
    registerIssue(
        message = "Variable `${variable.name}` of type `${variableDefinition.type.pretty()}` used in position expecting type `${variableUsage.locationType.pretty()}`",
        sourceLocation = variable.sourceLocation
    )
  }
}

private fun GQLInterfaceTypeDefinition.toIntrospectionType(): WTypeFull {
  return WTypeFull(
      kind = WTypeKind.INTERFACE,
      name = name,
      description = description,
      fields = fields.map { it.toIntrospectionField() },
      possibleTypes = typeDefinitions.values
          .filter { typeDefinition ->
            typeDefinition is GQLObjectTypeDefinition && typeDefinition.implementsInterfaces.contains(name)
          }
          .map { typeDefinition ->
            WTypeRef(
                kind = WTypeKind.OBJECT,
                name = typeDefinition.name,
                ofType = null
            )
          },
      interfaces = implementsInterfaces.map { interfaceName ->
        WTypeRef(
            kind = WTypeKind.INTERFACE,
            name = interfaceName,
            ofType = null
        )
      },
      enumValues = null,
      inputFields = null,
      specifiedByURL = null,
      isOneOf = null,
  )
}

override fun visitKtFile(file: KtFile) {
    val declarations = file.declarations
        .asSequence()
        .filterIsInstance<KtClassOrObject>()
        .filterNot { it.isPrivate() }
        .toList()

    fun matchesFirstClassOrObjectCondition(): Boolean =
        !mustBeFirst || (mustBeFirst && declarations.first() === file.declarations.first())

    fun hasNoMatchingTypeAlias(filename: String): Boolean =
        file.declarations.filterIsInstance<KtTypeAlias>().all { it.name != filename }

    if (declarations.size == 1 && matchesFirstClassOrObjectCondition()) {
        val declaration = declarations.first()
        val declarationName = declaration.name
        val filename = file.fileNameWithoutSuffix(multiplatformTargets)
        if (declarationName != filename && hasNoMatchingTypeAlias(filename)) {
            val entity = Entity.atName(declaration)
            report(
                Finding(
                    Entity(entity.signature, entity.location, file),
                    "The file name '$filename' " +
                        "does not match the name of the single top-level declaration '$declarationName'."
                )
            )
        }
    }
}

private fun KaSession.shouldReport(expression: KtExpression): Boolean {
    val expressionParent = getParentChainExpression(expression) ?: return false

    if (expressionParent.parent is KtProperty) {
        val property = expressionParent.parent as KtProperty
        if (property.parent is KtClassBody) {
            return false
        }
    }

    return when {
        expressionParent is KtQualifiedExpression -> {
            expressionParent.doesEndWithUse().not() &&
                expressionParent.firstCallableReceiverOrNull().isCloseableNotUsed()
        }

        isPartOfIfElseExpressionReturningCloseable(expression) -> {
            isExpressionUsedOnSameOrNextLine(expression).not()
        }

        isParentFunctionReturnsCloseable(expression) -> {
            false
        }

        isParamForClosableOrFunReturningClosable(expression) -> {
            false
        }

        expressionParent is KtProperty -> {
            traversedParentExpression.contains(expressionParent.children.getOrNull(0)).not()
        }

        else -> {
            true
        }
    }.also { traversedParentExpression.add(expressionParent) }
}

@Suppress("ReturnCount")
    override fun visitCallExpression(expression: KtCallExpression) {
        super.visitCallExpression(expression)

        val callee = expression.calleeExpression ?: return
        val argument = expression.valueArguments.firstOrNull()?.getArgumentExpression() ?: return

        analyze(expression) {
            if (expression
                    .resolveToCall()
                    ?.successfulFunctionCallOrNull()
                    ?.symbol
                    ?.callableId !in notNullCheckFunctionFqNames
            ) {
                return
            }
            if (expression.expressionType?.isNullable == true) return
        }

        analyze(argument) {
            if (argument.expressionType?.isNullable == true) return
        }

        report(
            Finding(
                entity = Entity.from(expression),
                message = "Using `${callee.text}` on non-null `${argument.text}` is unnecessary",
            )
        )
    }

override fun visitBlockExpression(expression: KtBlockExpression) {
    val statements = expression.statements
    val lastStatement = statements.lastOrNull() ?: return

    analyze(expression) {
        statements
            .filter {
                when {
                    it !is KtNameReferenceExpression || it.text != UNIT -> false

                    it != lastStatement -> true

                    !it.isUsedAsExpression -> true

                    else -> {
                        val prev =
                            it.siblings(forward = false, withItself = false).firstIsInstanceOrNull<KtExpression>()
                        prev?.expressionType?.isUnitType == true && prev.canBeUsedAsValue()
                    }
                }
            }
            .onEach {
                report(
                    Finding(
                        Entity.from(expression),
                        "A single Unit expression is unnecessary and can safely be removed."
                    )
                )
            }
    }

    super.visitBlockExpression(expression)
}

override fun visitClass(klass: KtClass) {
    classChain.add(klass)
    if (klass.isInner()) {
        candidateClassToParentClasses[klass] = findParentClasses(klass)
    }

    // Visit the class to determine whether it contains any references
    // to outer class members.
    super.visitClass(klass)

    val klassParent = candidateClassToParentClasses[klass]?.first()
    @Suppress("ComplexCondition")
    if (
        klass.isInner() &&
        candidateClassToParentClasses.containsKey(klass) &&
        // parent class is null or not inner or does not require to be inner
        (klassParent == null || !klassParent.isInner() || candidateClassToParentClasses.containsKey(klassParent))
    ) {
        report(
            Finding(
                Entity.Companion.from(klass),
                "Class '${klass.name}' does not require `inner` keyword."
            )
        )
        candidateClassToParentClasses.remove(klass)
    }
    classChain.removeLast()
}

private fun collectParameters(function: KtNamedFunction) {
    val parameters = mutableMapOf<String, KtParameter>()
    function.valueParameterList?.parameters?.forEach { parameter ->
        val name = parameter.nameAsSafeName.identifier
        if (!allowedNames.matches(name)) {
            parameters[name] = parameter
        }
    }

    function.accept(object : DetektVisitor() {
        override fun visitProperty(property: KtProperty) {
            if (property.isLocal) {
                val name = property.nameAsSafeName.identifier
                parameters.remove(name)
            }
            super.visitProperty(property)
        }

        override fun visitReferenceExpression(expression: KtReferenceExpression) {
            if (expression.parent !is KtValueArgumentName) {
                parameters.remove(expression.text.removeSurrounding("`"))
            }
            super.visitReferenceExpression(expression)
        }
    })

    unusedParameters.addAll(parameters.values)
}

@OptIn(KoinInternalApi::class)
fun KoinApplication.androidFileProperties(
    koinPropertyFile: String = "koin.properties",
): KoinApplication {
    val koinProperties = Properties()
    val androidContext = koin.get<Context>()
    try {
        val hasFile = androidContext.assets?.list("")?.contains(koinPropertyFile) ?: false
        if (hasFile) {
            try {
                androidContext.assets.open(koinPropertyFile).use { koinProperties.load(it) }
                val nb = koin.propertyRegistry.saveProperties(koinProperties)
                if (koin.logger.isAt(Level.INFO)) {
                    koin.logger.info("[Android-Properties] loaded $nb properties from assets/$koinPropertyFile")
                }
            } catch (e: Exception) {
                koin.logger.error("[Android-Properties] error for binding properties : $e")
            }
        } else {
            if (koin.logger.isAt(Level.INFO)) {
                koin.logger.info("[Android-Properties] no assets/$koinPropertyFile file to load")
            }
        }
    } catch (e: Exception) {
        koin.logger.error("[Android-Properties] error while loading properties from assets/$koinPropertyFile : $e")
    }
    return this
}

@KoinInternalApi
fun <T : Any> createDefinition(
    kclass: KClass<T>,
    definition: Definition<T>,
    qualifier: Qualifier? = null,
    scopeQualifier: Qualifier = rootScopeQualifier,
    factoryKind: Kind,
    module: Module,
    createdAtStart: Boolean = false
): KoinDefinition<T> {
    // Explicitly pass secondaryTypes for binary compatibility with Koin 4.1.x and 4.2.x
    val def = BeanDefinition(
        scopeQualifier,
        kclass,
        qualifier,
        definition,
        factoryKind,
        emptyList()  // secondaryTypes - explicit to avoid default parameter bytecode differences
    )
    val factory = when (factoryKind) {
        Kind.Singleton -> SingleInstanceFactory(def)
        Kind.Factory -> FactoryInstanceFactory(def)
        Kind.Scoped -> ScopedInstanceFactory(def)
    }
    module.indexPrimaryType(factory)

    // Handle createdAtStart for singletons
    if (createdAtStart && factoryKind == Kind.Singleton && factory is SingleInstanceFactory<*>) {
        module.eagerInstances.add(factory)
    }

    return KoinDefinition(module, factory)
}

fun Space.preparePackagesToDelete(packagesFile: File) {
    logger.quiet("Preparing list of packages for deletion. This may take some time...")

    val packagesToDelete = ArrayList<PackageInfo>()
    withSpaceClient {
        forEachPackage { pkg ->
            forEachVersion(pkg.name) { version ->
                if (FilenameUtils.wildcardMatch(version, packageVersionToDelete)) {
                    packagesToDelete.add(PackageInfo(name = pkg.name, version = version))
                }
            }
            logger.quiet("Analyzed package: ${pkg.name}")
        }
    }

    packagesFile.parentFile.mkdirs()
    packagesFile.writer().buffered().use { writer ->
        packagesToDelete.forEach {
            writer.write("#")
            writer.write(it.name)
            writer.write(":")
            writer.write(it.version)
            writer.newLine()
        }
    }

    logger.quiet("List of packages to delete is written to:\n    $packagesFile")
    logger.quiet("Uncomment packages you want to delete and rerun the task!")
}

internal inline fun Json.tryCoerceValue(
    descriptor: SerialDescriptor,
    index: Int,
    peekNull: (consume: Boolean) -> Boolean,
    peekString: () -> String?,
    onEnumCoercing: () -> Unit = {}
): Boolean {
    val isOptional = descriptor.isElementOptional(index)
    val elementDescriptor = descriptor.getElementDescriptor(index)
    if (isOptional && !elementDescriptor.isNullable && peekNull(true)) return true // (1)
    if (elementDescriptor.kind == SerialKind.ENUM) {
        if (elementDescriptor.isNullable && peekNull(false)) { // (2)
            return false
        }

        val enumValue = peekString()
            ?: return false // if value is not a string, decodeEnum() will throw correct exception
        val enumIndex = elementDescriptor.getJsonNameIndex(this, enumValue) // (3)
        val coerceToNull = !configuration.explicitNulls && elementDescriptor.isNullable // (4)
        if (enumIndex == CompositeDecoder.UNKNOWN_NAME && (isOptional || coerceToNull)) { // (3, 4, 5)
            onEnumCoercing()
            return true
        }
    }
    return false
}

internal fun SerialDescriptor.ignoreUnknownKeys(json: Json): Boolean =
    json.configuration.ignoreUnknownKeys || annotations.any { it is JsonIgnoreUnknownKeys }

fun getUnusedReports(): List<Finding> {
    val propertiesReport = classProperties
        .filter { it.psiOrParent !in usedClassProperties }
        .filter { !allowedNames.matches(it.nameAsSafeName.identifier) }
        .map {
            Finding(
                entity = Entity.atName(it),
                message = "Private property `${it.nameAsSafeName.identifier}` is unused."
            )
        }

    val constructorParametersReport = constructorParameters
        .filter { it.psiOrParent !in usedConstructorParameters }
        .filter { !allowedNames.matches(it.nameAsSafeName.identifier) }
        .map {
            Finding(
                entity = Entity.atName(it),
                message = "Constructor parameter `${it.nameAsSafeName.identifier}` is unused.",
            )
        }

    val topLevelPropertyReport = topLevelProperties
        .filter { it.psiOrParent !in usedTopLevelProperties }
        .filter { !allowedNames.matches(it.nameAsSafeName.identifier) }
        .map {
            Finding(
                entity = Entity.atName(it),
                message = "Private top level property `${it.nameAsSafeName.identifier}` is unused.",
            )
        }

    return propertiesReport + constructorParametersReport + topLevelPropertyReport
}

fun Project.configureAndroid(
    namespace: String,
    androidOptions: AndroidOptions
) {
  plugins.apply("com.android.library")

  extensions.findByName("android")?.apply {
    this as CommonExtension<*, *, *, *, *, *>

    compileSdk = getCatalogVersion("android.sdkversion.compile").toInt()
    this.namespace = namespace

    defaultConfig {
      minSdk = if (androidOptions.withCompose) {
        getCatalogVersion("android.sdkversion.compose.min").toInt()
      } else {
        getCatalogVersion("android.sdkversion.min").toInt()
      }
      testInstrumentationRunner = "androidx.test.runner.AndroidJUnitRunner"

      if (this is LibraryVariantDimension) {
        multiDexEnabled = true
      }
    }

    if (this is LibraryExtension) {
      @Suppress("UnstableApiUsage")
      testOptions.targetSdk = getCatalogVersion("android.sdkversion.target").toInt()
    }

    if (androidOptions.withCompose) {
      plugins.apply("org.jetbrains.kotlin.plugin.compose")
      buildFeatures {
        compose = true
      }
    }
  }
}

fun Project.configureMavenPublication(
    groupId: String,
    artifactId: String,
    name: String
) {
    extensions.configure<PublishingExtension> {
        publications {
            all {
                val publication = this as MavenPublication

                //work around to fix an android publication artifact ID
                //https://youtrack.jetbrains.com/issue/KT-53520
                afterEvaluate {
                    publication.groupId = groupId
                    publication.mppArtifactId = artifactId
                }

                pom {
                    this.name.set(name)
                    url.set("https://github.com/JetBrains/compose-multiplatform")
                    licenses {
                        license {
                            this.name.set("The Apache License, Version 2.0")
                            url.set("http://www.apache.org/licenses/LICENSE-2.0.txt")
                        }
                    }
                }
            }
        }
    }
}

